// Get the raw text from the Mistral response
const llmResponse = $input.first().json;
const reportData = $('Build Report Data (Deterministic)').first().json;

// Extract the content from the specific path Mistral uses
let narrativeText = llmResponse.choices?.[0]?.message?.content || "";

// Clean up any stray quotes or whitespace
narrativeText = narrativeText.trim();

// Since Mistral followed instructions and gave prose, 
// we use the whole thing as the summary.
let narrative = {
  summary: narrativeText,
  recommendation: 'Financial bids of eligible bidders may be opened as per schedule. Rejection letters to be issued to ineligible bidders with specific criterion references.'
};

// Merge into the report data
return [{
  json: {
    ...reportData,
    narrative
  }
}];

const d = $input.first().json;
const { 
  tender, 
  bidder_summaries: bidderCards, 
  unique_criteria: criteria, 
  narrative, 
  report_generated_at: generated_at 
} = d;

// Fix metadata filters to match 'overall_status'
const eligible = bidderCards.filter(b => b.overall_status === 'ELIGIBLE');
const ineligible = bidderCards.filter(b => b.overall_status === 'DISQUALIFIED');
const pending = bidderCards.filter(b => b.overall_status === 'PENDING_REVIEW');

const NAVY = '#1B3A6B';
const GREEN = '#1A5C35';
const GREEN_LIGHT = '#D4F0DC';
const RED = '#7A1F1F';
const RED_LIGHT = '#FAE0E0';
const AMBER = '#7A4E00';
const AMBER_LIGHT = '#FFF3CD';
const GRAY = '#595959';
const BORDER = '#CCCCCC';

function verdictBadge(verdict) {
  const map = {
    ELIGIBLE:      { bg: GREEN_LIGHT, color: GREEN,  label: 'ELIGIBLE' },
    DISQUALIFIED:  { bg: RED_LIGHT,   color: RED,    label: 'DISQUALIFIED' },
    PENDING_REVIEW:{ bg: AMBER_LIGHT, color: AMBER,  label: 'PENDING' },
    CONDITIONAL:   { bg: AMBER_LIGHT, color: AMBER,  label: 'CONDITIONAL' }
  };
  const s = map[verdict] || { bg: '#F2F4F7', color: GRAY, label: verdict };
  return `<span style="background:${s.bg};color:${s.color};font-weight:bold;padding:2px 8px;border-radius:3px;font-size:11px;font-family:Arial,sans-serif">${s.label}</span>`;
}

function th(text, width) {
  return `<th style="background:${NAVY};color:#ffffff;padding:8px 10px;text-align:left;font-family:Arial,sans-serif;font-size:12px;${width ? 'width:'+width+';' : ''}">${text}</th>`;
}
function td(text, extra) {
  return `<td style="padding:7px 10px;border-bottom:1px solid ${BORDER};font-family:Arial,sans-serif;font-size:12px;vertical-align:top;${extra||''}">${text||'—'}</td>`;
}
function tdCenter(text) {
  return `<td style="padding:7px 10px;border-bottom:1px solid ${BORDER};font-family:Arial,sans-serif;font-size:12px;text-align:center;vertical-align:middle;">${text||'—'}</td>`;
}

// ── Section: Master Eligibility Matrix ──
let matrixRows = '';
for (const bidder of bidderCards) {
  let criteriaVerdicts = '';
  for (const cr of bidder.criteria_results) {
    criteriaVerdicts += tdCenter(verdictBadge(cr.verdict_status)); // Fixed: verdict_status
  }
  matrixRows += `<tr>${td(bidder.bidder_name, 'font-weight:bold')}${criteriaVerdicts}${tdCenter(verdictBadge(bidder.overall_status))}</tr>`; // Fixed: overall_status
}

let matrixHeaders = th('Bidder', '180px');
for (const cr of criteria) {
  matrixHeaders += th(cr.criterion_id + '<br><span style="font-size:10px;font-weight:normal">' + cr.name + '</span>', '110px');
}
matrixHeaders += th('Overall', '100px');

const masterMatrix = `
<h2 style="color:${NAVY};font-family:Arial,sans-serif;font-size:15px;border-bottom:2px solid ${NAVY};padding-bottom:6px;margin-top:28px">Master Eligibility Matrix</h2>
<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;border:1px solid ${BORDER};margin-top:10px">
  <thead><tr>${matrixHeaders}</tr></thead>
  <tbody>${matrixRows}</tbody>
</table>`;

// ── Section: Per-Bidder Verdict Cards ──
let bidderSections = '';
for (const bidder of bidderCards) {
  const overallColor = bidder.overall_status === 'ELIGIBLE' ? GREEN : bidder.overall_status === 'DISQUALIFIED' ? RED : AMBER;
  const overallBg = bidder.overall_status === 'ELIGIBLE' ? GREEN_LIGHT : bidder.overall_status === 'DISQUALIFIED' ? RED_LIGHT : AMBER_LIGHT;

  let criterionRows = '';
  for (const cr of bidder.criteria_results) {
    criterionRows += `<tr>
      ${td(cr.criterion_id || '—')}
      ${td(cr.criterion_name, 'font-weight:bold')}
      ${td(cr.verdict_reason || '—')} 
      ${td(cr.evidence_text ? `<em style="font-size:11px;color:${GRAY}">&ldquo;${cr.evidence_text}&rdquo;</em><br>Page ${cr.evidence_pages.length ? cr.evidence_pages.join(',') : '?'}` : '—')}
      ${tdCenter(verdictBadge(cr.verdict_status))}
    </tr>`;
  }

  bidderSections += `
<div style="margin-top:24px;border:1px solid ${BORDER};border-radius:4px;overflow:hidden;page-break-inside:avoid">
  <div style="background:${overallBg};padding:12px 16px;border-bottom:2px solid ${overallColor}">
    <span style="font-family:Arial,sans-serif;font-size:14px;font-weight:bold;color:${overallColor}">${bidder.bidder_name}</span>
    <span style="float:right">${verdictBadge(bidder.overall_status)}</span>
  </div>
  <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">
    <thead><tr>${th('C#','40px')}${th('Criterion')}${th('Reason/Note')}${th('Source Evidence')}${th('Verdict','100px')}</tr></thead>
    <tbody>${criterionRows}</tbody>
  </table>
</div>`;
}

// ── Final HTML assembly ──
const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><style>@page { margin: 2cm; } body { font-family: Arial, sans-serif; font-size: 12px; color: #1A1A1A; }</style></head>
<body>
<table width="100%" style="margin-bottom:24px"><tr><td style="text-align:center;padding:16px;background:${NAVY};color:#ffffff">
<div style="font-size:16px;font-weight:bold">CENTRAL RESERVE POLICE FORCE (CRPF)</div>
<div style="font-size:11px">TECHNICAL BID EVALUATION REPORT — AI-ASSISTED</div></td></tr></table>

<h2 style="color:${NAVY};border-bottom:2px solid ${NAVY}">Evaluation Summary</h2>
<p>${narrative.summary}</p>
<p><strong>Recommendation:</strong> ${narrative.recommendation}</p>

${masterMatrix}
${bidderSections}

<div style="margin-top:48px;border-top:2px solid ${NAVY};padding-top:16px">
<div style="font-size:11px;color:${GRAY}">Generated by SmartTender AI — ${new Date(generated_at).toISOString()}</div>
</div>
</body></html>`;

return [{
  json: {
    tender_id: $('Webhook Trigger').first().json.body.tender_id,
    html_content: html,
    report_metadata: {
      tender_reference: tender.reference_number || tender.id,
      generated_at,
      total_bidders: bidderCards.length,
      eligible_count: eligible.length,
      ineligible_count: ineligible.length,
      pending_count: pending.length
    }
  }
}];
